@startuml
skinparam backgroundColor #eeeeee
skinparam componentStyle rectangle
skinparam ArrowColor red
skinparam ArrowThickness 1

' Outer virtualization layer
rectangle "KVM (L0)" as KVM #eeeeee {
}

' hAFL2 exists at top, interacting with all layers
component "hAFL2" as HAFL2 #bfaaff

' Hyper-V host layer
rectangle "Hyper-V (L1) - Host" as HyperV #ccf2ff {

    ' Root partition
    rectangle "Root Partition\nHost OS (L2)" as Root #a3d3f5 {
        component "vmswitch.sys" as VMSWITCH #d4a0f5
        component "CrashMonitoring.sys" as CRASHMON #d4a0f5
    }

    ' Child partition
    rectangle "Child Partition\nGuest VM (L2)" as Guest #7ec6f5 {
        component "harness.sys" as HARNESS #d4a0f5
    }

    HARNESS --> VMSWITCH : interaction
}

' Dotted interaction paths from hAFL2
HAFL2 <..> HARNESS
HAFL2 <..> CRASHMON
HAFL2 <..> VMSWITCH 

@enduml

@startuml
skinparam rectangle {
  BackgroundColor #ffffff
  BorderColor black
  Style roundrect
}
left to right direction

actor "Public Users"

cloud "Internet" as internet
rectangle "kubectl" as kubectl #blue

rectangle "AWS" {
  rectangle "VPC\n10.0.0.0/16" {

    rectangle "AZ-1a\nPublic Subnet" as az1a_pub {
      rectangle "Public LB" as public_lb #orange
    }

    rectangle "AZ-1a\nPrivate Subnet" as az1a_priv {
      rectangle "Worker Node 1" as worker1 #orange
      rectangle "Worker Node 2" as worker2 #orange
    }

    rectangle "AZ-1b\nPublic Subnet" as az1b_pub

    rectangle "AZ-1b\nPrivate Subnet" as az1b_priv {
      rectangle "Master Node" as master #orange
      rectangle "Worker Node 3" as worker3 #orange
    }

    rectangle "AZ-1c\nPublic Subnet" as az1c_pub {
      rectangle "Bastion Host" as bastion #orange
    }

    rectangle "AZ-1c\nPrivate Subnet" as az1c_priv {
      rectangle "Worker Node 4" as worker4 #orange
      rectangle "Worker Node 5" as worker5 #orange
    }

    rectangle "Private LB" as private_lb #orange
  }
}

"Public Users" --> public_lb
public_lb --> private_lb

private_lb --> master
private_lb --> worker1
private_lb --> worker2
private_lb --> worker3
private_lb --> worker4
private_lb --> worker5

bastion --> master
bastion --> worker3
bastion --> worker4
bastion --> worker5

kubectl --> private_lb
@enduml

@startuml
skinparam rectangle {
  BackgroundColor #ffffff
  BorderColor black
  Style roundrect
}
left to right direction

actor User

rectangle "Frontend" as FE {
}

rectangle "aeternity blockchain" as Blockchain #mistyrose {
  rectangle "PredictionCards\nSmart Contract" as Contract #palegreen
}

rectangle "process-prediction-\nservice" as PredictionService #lightsteelblue

rectangle "oracle-service" as OracleService #lightyellow

rectangle "IPFS" as IPFS #aliceblue

User --> FE

FE <--> Blockchain : create prediction\n deposit / rent NFT\n withdraw / claim rewards / get data\nvia dry-runs
FE <--> IPFS : load GIFs of NFTs

PredictionService --> Blockchain : poll for predictions with state "CLOSED"\ncall "ask_for_winning_option"
Blockchain --> PredictionService : call "process_oracle_response"\nif oracle responded

OracleService --> Blockchain : poll for oracle queries
OracleService --> Blockchain : respond to query with outcome (higher/lower)
OracleService --> OracleService : get price from coingecko API\n determine outcome
@enduml
